:root {
  --color-primary: #1a56db;
  --color-primary-hover: #1e429f;
  --radius-md: 8px;
  --space-md: 16px;
  --font-size-body: 16px;
}

.button-primary {
  background: var(--color-primary);
  border-radius: var(--radius-md);
  padding: var(--space-md);
  font-size: var(--font-size-body);
}
